    public static void pcabuildbasis(double[,] x, out double[] s2, out double[,] v)
    {
        int npoints;
        int nvars;

        s2 = new double[0];
        v = new double[0, 0];
        npoints = ap.rows(x);
        nvars = ap.cols(x);
        pca.pcabuildbasis(x, npoints, nvars, ref s2, ref v, null);

        return;
    }

    public static void pcabuildbasis(double[,] x, out double[] s2, out double[,] v, xparams _params)
    {
        int npoints;
        int nvars;

        s2 = new double[0];
        v = new double[0, 0];
