         Copyright 15.02.2019 by Bochkanov Sergey
    *************************************************************************/
    public static void knncreatebuffer(knnmodel model, out knnbuffer buf)
    {
        buf = new knnbuffer();
        knn.knncreatebuffer(model.innerobj, buf.innerobj, null);
    }

