    /*************************************************************************
    This function serializes data structure to string/stream.
    
    Important properties of s_out:
    * it contains alphanumeric characters, dots, underscores, minus signs
    * these symbols are grouped into words, which are separated by spaces
      and Windows-style (CR+LF) newlines
    * although  serializer  uses  spaces and CR+LF as separators, you can 
      replace any separator character by arbitrary combination of spaces,
      tabs, Windows or Unix newlines. It allows flexible reformatting  of
      the  string in case you want to include it into a text or XML file. 
      But you should not insert separators into the middle of the "words"
      nor should you change the case of letters.
    * s_out can be freely moved between 32-bit and 64-bit systems, little
      and big endian machines, and so on. You can serialize structure  on
      32-bit machine and unserialize it on 64-bit one (or vice versa), or
      serialize  it  on  SPARC  and  unserialize  on  x86.  You  can also 
      serialize it in C++ version of ALGLIB and unserialize it in C# one, 
      and vice versa.
    *************************************************************************/
    public static void spline1dserialize(spline1dinterpolant obj, out string s_out)
    {
       serializer s = new serializer();
        s.alloc_start();
        spline1d.spline1dalloc(s, obj.innerobj, null);
        s.sstart_str();
        spline1d.spline1dserialize(s, obj.innerobj, null);
        s.stop();
        s_out = s.get_string();
    }


