        k = ap.rows(a);
        minqp.minqpsetlc2dense(state.innerobj, a, al, au, k, null);

        return;
    }

    public static void minqpsetlc2dense(minqpstate state, double[,] a, double[] al, double[] au,xparams _params)
    {
